import React from 'react';

function Education({ data }) {
  if (!data) return null;

  return (
    <section id="education" className="py-12 md:py-16 bg-white">
      <div className="max-w-7xl mx-auto px-4">
        <p className="text-xs uppercase tracking-widest text-gray-500 font-semibold mb-12">
          Formation
        </p>

        <div className="space-y-12">
          {data.map((edu) => (
            <div key={edu.id} className="border-b border-gray-200 pb-12 last:border-0 flex gap-6 hover:bg-gray-50 p-6 rounded-lg transition">
              {/* Icon or Image */}
              {edu.image ? (
                <div className="flex-shrink-0 w-20 h-20 flex items-center justify-center bg-gray-100 rounded-lg overflow-hidden">
                  <img src={edu.image} alt={edu.institution} className="w-full h-full object-cover" />
                </div>
              ) : edu.icon ? (
                <div className="flex-shrink-0 w-16 h-16 flex items-center justify-center bg-gray-100 rounded-lg text-2xl">
                  {edu.icon}
                </div>
              ) : null}
              
              {/* Content */}
              <div className="flex-1">
                <div className="flex items-start justify-between mb-2">
                  <h3 className="text-xl font-black text-gray-900">
                    {edu.institution}
                  </h3>
                </div>
                <p className="text-base font-semibold text-gray-700 mb-2">
                  {edu.degree}
                </p>
                <div className="flex flex-col gap-2 mb-3">
                  <p className="text-sm text-gray-600 flex items-center gap-2">
                    <span className="text-gray-400">📅</span> {edu.period}
                  </p>
                  {edu.location && (
                    <p className="text-sm text-gray-600 flex items-center gap-2">
                      <span className="text-gray-400">📍</span> {edu.location}
                    </p>
                  )}
                </div>
                {edu.details && (
                  <div className="bg-gray-100 border-l-2 border-gray-400 pl-3 py-2 rounded">
                    <p className="text-sm text-gray-700 leading-relaxed">✓ {edu.details}</p>
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export default Education;
